await new Promise(r => setTimeout(r, 500));
return [{
  json: {
    status: 'trained',
    model_version: '1.0.0',
    trained_at: new Date().toISOString(),
    samples_used: 142
  }
}];

const profiles = ['Familles', 'Jeunes adultes', 'Seniors', 'Professionnels'];
const niveaux = ['Faible', 'Modéré', 'Élevé', 'Très élevé'];
const visiteurs = Math.floor(Math.random() * 300) + 350;

return [{
  json: {
    visiteurs_prevus: visiteurs,
    profil_dominant: profiles[Math.floor(Math.random() * profiles.length)],
    niveau_affluence: niveaux[Math.floor(Math.random() * niveaux.length)],
    heure_pointe_debut: '14:00',
    heure_pointe_fin: '18:00',
    date_prevision: new Date().toISOString().split('T')[0]
  }
}];

const data = $input.first().json;

const prompt = `Tu es l assistant analytique de ShopAnalytics pour Anavid Store 360. Voici les predictions de frequentation pour aujourd hui (${data.date_prevision}) : Visiteurs prevus : ${data.visiteurs_prevus}. Profil dominant : ${data.profil_dominant}. Niveau d affluence : ${data.niveau_affluence}. Heure de pointe : ${data.heure_pointe_debut} a ${data.heure_pointe_fin}. Redige un message professionnel et concis de 4 a 5 phrases en francais a destination de l equipe du magasin. Mentionne le nombre de visiteurs, le profil dominant, le niveau d affluence et donne 1 a 2 recommandations concretes sur la gestion du personnel ou des caisses.`;

return [{
  json: {
    prompt: prompt,
    prediction: data
  }
}];

// Formate le payload attendu par Django SSE (receive_daily_report)
// et par le Dashboard.tsx (PredictionData interface)
const llmText = $input.first().json.text?.trim();
const pred = $('Préparer Prompt Ollama').first().json.prediction;

const payload = {
  type: 'llm_report',
  date: pred.date_prevision,
  generated_at: new Date().toISOString(),
  message: llmText,
  prediction: {
    visiteurs_prevus: pred.visiteurs_prevus,
    profil_dominant:  pred.profil_dominant,
    niveau_affluence: pred.niveau_affluence,
    heure_pointe:     `${pred.heure_pointe_debut} - ${pred.heure_pointe_fin}`
  }
};

return [{ json: payload }];

// Appel HTTP via $http natif de N8N (fetch et http sont bloqués)
const llmText = $input.first().json.text?.trim();
const prediction = $('Préparer Prompt Ollama').first().json.prediction;

let chatAnswer = llmText;

try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://django_api:8000/api/chat/',
    headers: { 'Content-Type': 'application/json' },
    body: {
      question: `Rapport quotidien automatique du ${prediction.date_prevision} : ${llmText}`
    },
    json: true
  });
  chatAnswer = response.answer || llmText;
} catch (err) {
  console.log('Django indisponible, fallback LLM : ' + err.message);
}

const notification = {
  id: Date.now(),
  date: prediction.date_prevision,
  generated_at: new Date().toISOString(),
  visiteurs_prevus: prediction.visiteurs_prevus,
  profil_dominant: prediction.profil_dominant,
  niveau_affluence: prediction.niveau_affluence,
  heure_pointe: `${prediction.heure_pointe_debut} - ${prediction.heure_pointe_fin}`,
  message: chatAnswer,
  model: 'llama3.2:3b-instruct-q4_K_M',
  type: 'daily_report'
};

return [{ json: notification }];

